    "trigger_definition": "CREATE TRIGGER trg_stock_ledger_updated_at BEFORE UPDATE ON stock_ledger FOR EACH ROW EXECUTE FUNCTION fn_set_stock_ledger_updated_at()",
    "function_body": "CREATE OR REPLACE FUNCTION public.fn_set_stock_ledger_updated_at()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  NEW.updated_at = now();\r\n  RETURN NEW;\r\nEND;\r\n$function$\n"
